previewCss:
.darma-loader-darma-custom-628 {color: var(--loader-color, #ca8a04);
  --loader-secondary-color: #fde047;
  --loader-bg: #ffffff;
   width: 70px;
   aspect-ratio: 1;
   background: radial-gradient(farthest-side,currentColor 90%,#0000) 0 0/8px 8px no-repeat, conic-gradient(from -90deg at 30px 30px,#0000 90deg,currentColor 0) 0 0/40px 40px , conic-gradient(from 90deg at 10px 10px,#0000 90deg,currentColor 0) 0 0/40px 40px no-repeat, conic-gradient(from -90deg at 30px 30px,#0000 90deg,currentColor 0) 100% 100%/40px 40px no-repeat;
   animation: darma-loader-darma-custom-628-l5 2s infinite;
}
@keyframes darma-loader-darma-custom-628-l5  {
  0% {background-position:left 1px top 1px,0 0,0 0,100% 100%}
16.67% {background-position:left 50% top 1px,0 0,0 0,100% 100%}
33.33% {background-position:left 50% bottom 1px,0 0,0 0,100% 100%}
50% {background-position:right 1px bottom 1px,0 0,0 0,100% 100%}
66.67% {background-position:right 1px bottom 50%,0 0,0 0,100% 100%}
83.33% {background-position:left 1px bottom 50%,0 0,0 0,100% 100%}
100% {background-position:left 1px top 1px,0 0,0 0,100% 100%}
}

